SAFETY_FALSE = {
    "approved_for_exchange_submit": False,
    "approved_for_live_real": False,
    "approved_for_paper_transition": False,
    "approved_for_runtime_overlay": False,
    "archive_execution_allowed": False,
    "archive_move_performed": False,
    "deduplication_action_performed": False,
    "destructive_cleanup_performed": False,
    "exchange_submit_performed": False,
    "file_delete_performed": False,
    "file_move_performed": False,
    "next_phase_unlock_performed": False,
    "order_submit_performed": False,
    "approval_performed": False,
    "simulated_approval_performed": False,
    "reload_performed": False,
    "report_delete_performed": False,
    "runtime_overlay_activated": False,
    "trading_action_performed": False,
    "training_performed": False,
    "transition_to_next_phase_performed": False,
}


def _utc_timestamp() -> str:
    return _dt.datetime.now(tz=_dt.timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def main() -> int:
    root = Path.cwd()
    backup_root = root / "tools" / f"_patch_backup_{PATCH_ID}_{_utc_timestamp()}"
    backed_up: list[str] = []
    written: list[str] = []
    modified: list[str] = []

    for rel_text, content in FILES.items():
        dest = root / rel_text
        old_content = dest.read_text(encoding="utf-8") if dest.exists() and dest.is_file() else None
        if old_content is not None and old_content != content:
            backup = backup_root / rel_text
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(dest, backup)
            backed_up.append(rel_text)
            modified.append(rel_text)
        elif old_content is None:
            modified.append(rel_text)
        dest.parent.mkdir(parents=True, exist_ok=True)
        dest.write_text(content, encoding="utf-8", newline="\n")
        written.append(rel_text)

    compile_errors: dict[str, str] = {}
    for rel_text in written:
        if rel_text.endswith(".py"):
            try:
                py_compile.compile(str(root / rel_text), doraise=True)
            except py_compile.PyCompileError as exc:
                compile_errors[rel_text] = str(exc)

    result = {
        "applied": not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "backup_root": str(backup_root.relative_to(root)) if backed_up else "",
        "backed_up_files": backed_up,
        "modified_files": modified,
        "written_files": written,
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        **SAFETY_FALSE,
    }
    print(json.dumps(result, indent=2, sort_keys=True, ensure_ascii=False))
    return 0 if not compile_errors else 1


if __name__ == "__main__":
    raise SystemExit(main())
